-- Kenya Electoral Boundaries
-- Auto-generated from Kenya_Wards Shapefile (verified IEBC data)
-- 47 Counties | 290 Constituencies | 1450 Wards
-- Source: lib/Kenya_Wards/kenya_wards.shp

-- ==========================================
-- CREATE LOCATION TABLES
-- ==========================================

CREATE TABLE IF NOT EXISTS counties (
  id TEXT PRIMARY KEY,
  name VARCHAR(255) NOT NULL UNIQUE,
  population_2009 INTEGER,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP
);

CREATE TABLE IF NOT EXISTS constituencies (
  id TEXT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  county_id TEXT NOT NULL REFERENCES counties(id),
  population_2009 INTEGER,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(county_id, name)
);

CREATE TABLE IF NOT EXISTS wards (
  id TEXT PRIMARY KEY,
  name VARCHAR(255) NOT NULL,
  constituency_id TEXT NOT NULL REFERENCES constituencies(id),
  ward_uid VARCHAR(50),
  population_2009 INTEGER,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  UNIQUE(constituency_id, name)
);

CREATE INDEX IF NOT EXISTS idx_constituencies_county ON constituencies(county_id);
CREATE INDEX IF NOT EXISTS idx_wards_constituency ON wards(constituency_id);

